    for i in range(m):
        u = arr[3 + 2 * i]
        v = arr[3 + 2 * i + 1]
        adj[u].append(v)

    match_right = [-1] * n_right

    def dfs(u, visited):
        for v in adj[u]:
            if not visited[v]:
